   105→TEST(ArcReplacerTest, DISABLED_SampleTest2) {
   106→  // Test a smaller capacity
   107→  ArcReplacer arc_replacer(3);
   108→  // Fill up the replacer
   109→  arc_replacer.RecordAccess(1, 1);
   110→  arc_replacer.SetEvictable(1, true);
   111→  arc_replacer.RecordAccess(2, 2);
   112→  arc_replacer.SetEvictable(2, true);
   113→  arc_replacer.RecordAccess(3, 3);
   114→  arc_replacer.SetEvictable(3, true);
   115→  ASSERT_EQ(3, arc_replacer.Size());
   116→  // Now [][(1,f1), (2,f2), (3,f3)]![][] p=0
   117→  // Evict all pages
   118→  ASSERT_EQ(1, arc_replacer.Evict());
   119→  ASSERT_EQ(2, arc_replacer.Evict());
   120→  ASSERT_EQ(3, arc_replacer.Evict());
   121→  ASSERT_EQ(0, arc_replacer.Size());
   122→  // Now [(1,_), (2,_), (3,_)][]![][] p=0
   123→
   124→  // Insert a new page 4 with frame 3. This is case 4A
   125→  // and ghost pages 1 should be driven out
   126→  arc_replacer.RecordAccess(3, 4);
   127→  arc_replacer.SetEvictable(3, true);
   128→  // Now [(2,_), (3,_)][(4,f3)]![][] p=0
   129→
   130→  // Access page 1 on frame 2, it should NOT be a hit on
   131→  // the ghost list. Ghost page 2 should be driven out
   132→  arc_replacer.RecordAccess(2, 1);
   133→  arc_replacer.SetEvictable(2, true);
   134→  ASSERT_EQ(2, arc_replacer.Size());
   135→  // Now [(3,_)][(4,f3), (1,f2)]![][] p=0
   136→
   137→  // Access page 3 with frame 1, this should be a ghost hit,
   138→  // page 3 is placed on mfu and target size is bumped up by 1
   139→  arc_replacer.RecordAccess(1, 3);
   140→  arc_replacer.SetEvictable(1, true);
   141→  // Now [][(4,f3), (1,f2)]![(3,f1)][] p=1
   142→
   143→  // Make some more ghosts by evicting all pages again
   144→  ASSERT_EQ(3, arc_replacer.Evict());
   145→  ASSERT_EQ(2, arc_replacer.Evict());
   146→  ASSERT_EQ(1, arc_replacer.Evict());
   147→  // Now [(4,_), (1,_)][]![][(3,_)] p=1
   148→
   149→  // Let's make even more ghost to fill the list to "full"
   150→  // Insert page 1 again so it goes to mfu side,
   151→  // target is bumped up by 1
   152→  arc_replacer.RecordAccess(1, 1);
   153→  arc_replacer.SetEvictable(1, true);
